const sqlRow = $input.item.json;

if (!sqlRow || !sqlRow.instance_name) {
  throw new Error('Dados da instância não encontrados no resultado SQL');
}

// === Normalizar dados do SQL para o formato padrão ===
const instancia = {
  id: sqlRow.id,
  instanceId: sqlRow.instance_id,
  instanceName: sqlRow.instance_name,
  integration: sqlRow.integration,
  personality: sqlRow.personality || '',
  description: sqlRow.description || null,
  phoneNumber: sqlRow.phone_number || null,
  profilePictureUrl: sqlRow.profile_picture_url || null,
  profileName: sqlRow.profile_name || null,
  organizacaoId: sqlRow.organizacao_id,
  organizacaoNome: sqlRow.organizacao_nome || '',
  instanceAtivo: sqlRow.ativo === true,
  tools: {
    getServices: sqlRow.get_services === true,
    getProfessional: sqlRow.get_professional === true,
    getProducts: sqlRow.get_products === true,
    getAvaliableSchedules: sqlRow.get_avaliable_schedules === true,
    postScheduling: sqlRow.post_scheduling === true,
    sendTextMessage: sqlRow.send_text_message === true,
    sendMediaMessage: sqlRow.send_media_message === true,
    postConfirmations: sqlRow.post_confirmations === true,
    postCancellations: sqlRow.post_cancellations === true
  },
  webhookSettings: {
    url: sqlRow.url || null,
    enabled: sqlRow.enabled === true,
    events: sqlRow.events ? (typeof sqlRow.events === 'string' ? JSON.parse(sqlRow.events) : sqlRow.events) : []
  },
  settings: {
    rejectCall: sqlRow.reject_call === true,
    msgCall: sqlRow.msg_call || '',
    groupsIgnore: sqlRow.groups_ignore === true,
    alwaysOnline: sqlRow.always_online === true,
    readMessages: sqlRow.read_messages === true,
    readStatus: sqlRow.read_status === true
  },
  knowledgeBase: [],
  apiKey: {
    name: sqlRow.name,
    apikey: sqlRow.apikey,
    ativo: sqlRow.ativo
  }
};

// Se houver dados de knowledge base
if (sqlRow.title && sqlRow.content) {
  instancia.knowledgeBase.push({
    title: sqlRow.title,
    type: sqlRow.type,
    content: sqlRow.content,
    fileName: sqlRow.file_name,
    fileSize: sqlRow.file_size,
    fileType: sqlRow.file_type,
    fileUrl: sqlRow.file_url
  });
}

const tools = instancia.tools;
const instanceAtivo = instancia.instanceAtivo;

let knowledgeBaseText = '';
if (instancia.knowledgeBase && instancia.knowledgeBase.length > 0) {
  knowledgeBaseText = '\n\n=== BASE DE CONHECIMENTO ===\n';
  instancia.knowledgeBase.forEach(kb => {
    if (kb.type === 'TEXT' && kb.content) {
      knowledgeBaseText += `\n### ${kb.title}\n${kb.content}\n`;
    }
  });
  knowledgeBaseText += '\n========================\n';
}

// === GERAR LISTA DE TOOLS HABILITADAS/DESABILITADAS ===
const toolsList = [];
if (tools.getServices) {
  toolsList.push('- listar_categorias: Listar categorias de serviços');
  toolsList.push('- buscar_servicos_categoria: Consultar serviços de uma categoria');
  toolsList.push('- buscar_todos_servicos: Listar todos os serviços com preços e duração');
}
if (tools.getProfessional) {
  toolsList.push('- buscar_profissionais_servico: Consultar profissionais que realizam um serviço');
}
if (tools.getAvaliableSchedules) {
  toolsList.push('- buscar_disponibilidade: Consultar horários disponíveis para agendamento');
}
if (tools.postScheduling) {
  toolsList.push('- consultar_cliente: Verificar se cliente já existe pelo telefone');
  toolsList.push('- salvar_cliente: Cadastrar novo cliente rápido');
  toolsList.push('- salvar_agendamento: Criar/salvar novo agendamento');
  toolsList.push('- gerenciar_sessao: Gerenciar sessão/progresso do agendamento');
}

const toolsInfo = toolsList.length > 0
  ? '\n\n=== FERRAMENTAS DISPONÍVEIS ===\nVocê pode usar APENAS estas ferramentas:\n' + toolsList.join('\n') + '\n\nNÃO use ferramentas que não estão listadas acima.\n\n=== FLUXO DE AGENDAMENTO ===\nSiga esta ordem para agendar:\n1. Use consultar_cliente para verificar se o cliente existe (pelo telefone)\n2. Se NÃO existir, peça o nome e use salvar_cliente para cadastrar\n3. Apresente os serviços: listar_categorias ou buscar_todos_servicos\n4. Após escolher serviço: buscar_profissionais_servico\n5. Após escolher profissional: buscar_disponibilidade\n6. Quando TUDO estiver definido e o cliente confirmar: salvar_agendamento\n7. Use gerenciar_sessao para salvar o progresso a cada etapa\n\nIMPORTANTE:\n- SEMPRE consulte o cliente antes de salvar agendamento\n- NUNCA pule etapas do fluxo\n- Use gerenciar_sessao para não perder o contexto entre mensagens\n==============================\n'
  : '\n\n=== AVISO ===\nNenhuma ferramenta está habilitada. Responda apenas com base no seu conhecimento e na base de conhecimento fornecida.\n=============\n';

return [{
  json: {
    instance_id: instancia.id,
    instance_name: instancia.instanceName,
    instance_ativo: instanceAtivo,
    personality: instancia.personality || 'Você é um assistente virtual profissional e cordial.',
    knowledge_base_text: knowledgeBaseText,
    tools_info: toolsInfo,
    organizacao_id: instancia.organizacaoId,
    organizacao_nome: instancia.organizacaoNome,
    api_key: instancia.apiKey.apikey,
    tools_enabled: {
      get_services: tools.getServices === true,
      get_professional: tools.getProfessional === true,
      get_products: tools.getProducts === true,
      get_avaliable_schedules: tools.getAvaliableSchedules === true,
      post_scheduling: tools.postScheduling === true,
      send_text_message: tools.sendTextMessage === true,
      send_media_message: tools.sendMediaMessage === true,
      post_confirmations: tools.postConfirmations === true,
      post_cancellations: tools.postCancellations === true
    },
    remetente_numero: $('Normalizar Dados').item.json.remetente_numero,
    remetente_nome: $('Normalizar Dados').item.json.remetente_nome,
    mensagem_texto: $('Normalizar Dados').item.json.mensagem_texto,
    telefone_limpo: $('Normalizar Dados').item.json.telefone_limpo,
    remotejid: $('Normalizar Dados').first().json.body.data.key.remoteJidAlt
  }
}];

// ════════════════════════════════════════════════════════
// ROTEAMENTO POR FUNCIONALIDADE
// Determina qual caminho seguir baseado em:
// - instance_ativo: se a instância (agente) está ativa
// - post_confirmations: se confirmação/lembrete está ativo
//
// Saídas:
// Output 0: TUDO ATIVO (instance_ativo=true E post_confirmations=true)
//           → Verifica notificação pendente, se não tiver vai pro agente
// Output 1: SÓ CONFIRMAÇÃO (instance_ativo=false E post_confirmations=true)
//           → Só verifica notificação pendente, se não tiver para
// Output 2: SÓ AGENTE (instance_ativo=true E post_confirmations=false)
//           → Vai direto pro buffer/agente, ignora notificações
// Output 3: NADA ATIVO (instance_ativo=false E post_confirmations=false)
//           → Não faz nada
// ════════════════════════════════════════════════════════

const data = $input.item.json;
const instanceAtivo = data.instance_ativo === true;
const postConfirmations = data.tools_enabled.post_confirmations === true;

// Determinar a rota
let rota = '';
if (instanceAtivo && postConfirmations) {
  rota = 'TUDO_ATIVO';
} else if (!instanceAtivo && postConfirmations) {
  rota = 'SO_CONFIRMACAO';
} else if (instanceAtivo && !postConfirmations) {
  rota = 'SO_AGENTE';
} else {
  rota = 'NADA_ATIVO';
}

return [{
  json: {
    ...data,
    rota_funcionalidade: rota
  }
}];

// ════════════════════════════════════════════════════════
// CLASSIFICAR RESPOSTA DE CONFIRMAÇÃO
// Analisa a mensagem do cliente e determina a ação
// baseado no status atual da notificação
// ════════════════════════════════════════════════════════

const notificacao = $input.item.json;
const msg = $('Processar Dados Instância').item.json.mensagem_texto;
const instanceData = $('Processar Dados Instância').item.json;

const msgLower = msg.toLowerCase()
  .normalize('NFD')
  .replace(/[\u0300-\u036f]/g, '')
  .trim();

const status = notificacao.notif_status;
let action = 'ERRO';
let responseText = '';
let needsTimesQuery = false;
let parsedDate = null;
let selectedTime = null;
let updateNotifStatus = null;
let updateAgendStatus = null;
let respostaCliente = null;

// ═══ ESTADO: AGUARDANDO_RESPOSTA (SIM/NAO/REAGENDAR) ═══
if (status === 'AGUARDANDO_RESPOSTA') {
  const simKeywords = ['sim', 'confirmo', 'confirmado', 'pode confirmar', 'vou sim',
    'ok', 'ta bom', 'vou', 'combinado', 'fechado', 'perfeito', 'isso',
    'certo', 'claro', 'com certeza', 'positivo', 's', 'ss', 'siin', 'siim',
    'pode ser', 'confirma', 'confirmando', 'vou estar', 'estarei ai'];

  const naoKeywords = ['nao', 'cancela', 'cancelar', 'nao posso', 'nao vou',
    'desmarcar', 'nao vai dar', 'n', 'nn', 'nnn', 'desisto',
    'nao quero', 'cancele', 'remove', 'tira'];

  const reagendarKeywords = ['reagendar', 'remarcar', 'mudar', 'trocar',
    'outro dia', 'outra data', 'outro horario', 'adiar', 'alterar',
    'transferir', 'mudar data', 'mudar horario', 'trocar dia'];

  if (simKeywords.some(k => msgLower.includes(k))) {
    action = 'CONFIRMAR';
    updateNotifStatus = 'CONFIRMADO';
    updateAgendStatus = 'CONFIRMADO';
    respostaCliente = 'SIM';
    responseText = `✅ Seu agendamento foi *CONFIRMADO* com sucesso!\n\nAguardamos você no horário marcado. 😊`;
  }else if (reagendarKeywords.some(k => msgLower.includes(k))) {
    action = 'PEDIR_DATA';
    updateNotifStatus = 'AGUARDANDO_DATA';
    respostaCliente = 'REAGENDAR';
    responseText = `📅 Entendido! Para qual data você gostaria de reagendar?\n\nPor favor, informe a data desejada no formato:\n*DD/MM/AAAA* (ex: 15/02/2026)`;
  }else if (naoKeywords.some(k => msgLower.includes(k))) {
    action = 'CANCELAR';
    updateNotifStatus = 'CANCELADO_CLIENTE';
    updateAgendStatus = 'CANCELADO';
    respostaCliente = 'NAO';
    responseText = `❌ Seu agendamento foi *CANCELADO*.\n\nSe precisar, faça um novo agendamento quando desejar. 😊`;
  } else {
    action = 'RESPOSTA_INVALIDA';
    responseText = `Desculpe, não entendi sua resposta. 🤔\n\nPor favor, responda com:\n\n✅ *SIM* - para confirmar\n❌ *NÃO* - para cancelar\n📅 *REAGENDAR* - para remarcar`;
  }
}

// ═══ ESTADO: AGUARDANDO_DATA (cliente deve informar data) ═══
else if (status === 'AGUARDANDO_DATA') {
  const regexData = /(\d{1,2})[\/\-](\d{1,2})[\/\-](\d{4})/;
  const match = msg.match(regexData);

  if (match) {
    const dia = parseInt(match[1]);
    const mes = parseInt(match[2]) - 1;
    const ano = parseInt(match[3]);
    const dataObj = new Date(ano, mes, dia);
    const hoje = new Date();
    hoje.setHours(0, 0, 0, 0);

    if (dataObj.getDate() === dia &&
        dataObj.getMonth() === mes &&
        dataObj.getFullYear() === ano &&
        dataObj > hoje) {
      action = 'BUSCAR_HORARIOS';
      needsTimesQuery = true;
      parsedDate = `${ano}-${String(mes + 1).padStart(2, '0')}-${String(dia).padStart(2, '0')}`;
      // Dia da semana para consulta de jornada (0=domingo, 6=sábado)
      const diasSemana = ['DOMINGO', 'SEGUNDA', 'TERCA', 'QUARTA', 'QUINTA', 'SEXTA', 'SABADO'];
      const diaSemanaIdx = dataObj.getDay();
      parsedDate = {
        iso: `${ano}-${String(mes + 1).padStart(2, '0')}-${String(dia).padStart(2, '0')}`,
        formatted: `${String(dia).padStart(2, '0')}/${String(mes + 1).padStart(2, '0')}/${ano}`,
        diaSemana: diasSemana[diaSemanaIdx],
        diaSemanaIdx: diaSemanaIdx
      };
    } else {
      action = 'DATA_INVALIDA';
      responseText = `⚠️ Data inválida ou no passado.\n\nPor favor, informe uma data *futura* no formato *DD/MM/AAAA*.`;
    }
  } else {
    action = 'DATA_INVALIDA';
    responseText = `⚠️ Formato de data não reconhecido.\n\nPor favor, informe no formato *DD/MM/AAAA* (ex: 15/02/2026).`;
  }
}

// ═══ ESTADO: AGUARDANDO_HORARIO (cliente deve escolher horário) ═══
else if (status === 'AGUARDANDO_HORARIO') {
  const selecao = parseInt(msgLower.replace(/[^0-9]/g, ''));
  let horarios = [];
  try {
    horarios = JSON.parse(notificacao.horarios_disponiveis || '[]');
  } catch(e) {
    horarios = [];
  }

  if (!isNaN(selecao) && selecao >= 1 && selecao <= horarios.length) {
    action = 'REAGENDAR';
    selectedTime = horarios[selecao - 1];
    updateNotifStatus = 'REAGENDADO';
    updateAgendStatus = 'REAGENDADO';
    respostaCliente = `HORARIO_${selecao}`;

    const dataReagend = notificacao.data_desejada_reagendamento;
    let dataFormatted = dataReagend;
    if (dataReagend && dataReagend.includes('-')) {
      const [a, m, d] = dataReagend.split('-');
      dataFormatted = `${d}/${m}/${a}`;
    }

    responseText = `✅ Seu agendamento foi *REAGENDADO* com sucesso!\n\n📅 Nova data: *${dataFormatted}*\n🕐 Horário: *${selectedTime.horaInicio}*\n\nAguardamos você! 😊`;
  } else {
    action = 'SELECAO_INVALIDA';
    responseText = `⚠️ Seleção inválida.\n\nPor favor, responda com o *número* do horário desejado (1, 2, 3...).`;
  }
}

return [{
  json: {
    action,
    needsTimesQuery,
    responseText,
    parsedDate,
    selectedTime,
    updateNotifStatus,
    updateAgendStatus,
    respostaCliente,
    notificacao_id: notificacao.notificacao_id,
    agendamento_id: notificacao.agendamento_id,
    notif_status: notificacao.notif_status,
    cliente_nome: notificacao.cliente_nome,
    organizacao_id: notificacao.organizacao_id,
    organizacao_nome: notificacao.organizacao_nome,
    instance_name: instanceData.instance_name,
    remetente_numero: instanceData.remetente_numero,
    telefone_limpo: instanceData.telefone_limpo,
    data_desejada_reagendamento: notificacao.data_desejada_reagendamento,
    horarios_disponiveis: notificacao.horarios_disponiveis
  }
}];

// ════════════════════════════════════════════════════════
// CALCULAR HORÁRIOS DISPONÍVEIS
// Com base na jornada do funcionário e horários ocupados
// ════════════════════════════════════════════════════════

const dados = $input.item.json;
const classif = $('Classificar Resposta Confirmação').item.json;

// Verificar se tem jornada para o dia
if (!dados.jornada_inicio || !dados.jornada_fim) {
  return [{
    json: {
      ...classif,
      horariosDisponiveis: [],
      temHorarios: false,
      responseText: `⚠️ O profissional *${dados.nome_funcionario || 'selecionado'}* não trabalha neste dia.\n\nPor favor, informe outra data no formato *DD/MM/AAAA*.`
    }
  }];
}

// Parse jornada
const [iniH, iniM] = dados.jornada_inicio.split(':').map(Number);
const [fimH, fimM] = dados.jornada_fim.split(':').map(Number);
const duracaoServico = dados.tempo_estimado_minutos || 30;

// Parse horários ocupados
let ocupados = [];
try {
  ocupados = typeof dados.horarios_ocupados === 'string'
    ? JSON.parse(dados.horarios_ocupados)
    : dados.horarios_ocupados || [];
} catch(e) {
  ocupados = [];
}

// Gerar slots disponíveis
const slots = [];
let currentMinutes = iniH * 60 + iniM;
const endMinutes = fimH * 60 + fimM;

while (currentMinutes + duracaoServico <= endMinutes) {
  const slotHora = Math.floor(currentMinutes / 60);
  const slotMinuto = currentMinutes % 60;

  // Verificar se conflita com algum horário ocupado
  const conflito = ocupados.some(oc => {
    const ocInicio = (oc.hora || 0) * 60 + (oc.minuto || 0);
    const ocFim = ocInicio + (oc.duracao || 30);
    const slotInicio = currentMinutes;
    const slotFim = currentMinutes + duracaoServico;
    return slotInicio < ocFim && slotFim > ocInicio;
  });

  if (!conflito) {
    const horaStr = `${String(slotHora).padStart(2, '0')}:${String(slotMinuto).padStart(2, '0')}`;
    const fimSlot = currentMinutes + duracaoServico;
    const fimHoraStr = `${String(Math.floor(fimSlot / 60)).padStart(2, '0')}:${String(fimSlot % 60).padStart(2, '0')}`;
    slots.push({ horaInicio: horaStr, horaFim: fimHoraStr });
  }

  currentMinutes += 30; // Incremento de 30 minutos
}

// Formatar mensagem com horários
let responseText;
if (slots.length > 0) {
  const dataFormatted = classif.parsedDate.formatted;
  responseText = `📅 Horários disponíveis para *${dataFormatted}*`;
  if (dados.nome_funcionario) responseText += ` com *${dados.nome_funcionario}*`;
  responseText += `:\n\n`;
  slots.forEach((slot, idx) => {
    responseText += `*${idx + 1}* - ${slot.horaInicio} às ${slot.horaFim}\n`;
  });
  responseText += `\nResponda com o *número* do horário desejado.`;
} else {
  responseText = `⚠️ Não há horários disponíveis para *${classif.parsedDate.formatted}*.\n\nPor favor, informe outra data no formato *DD/MM/AAAA*.`;
}

return [{
  json: {
    ...classif,
    horariosDisponiveis: slots,
    temHorarios: slots.length > 0,
    responseText,
    nome_funcionario: dados.nome_funcionario,
    nome_servico: dados.nome_servico,
    updateNotifStatus: slots.length > 0 ? 'AGUARDANDO_HORARIO' : null
  }
}];

// ════════════════════════════════════════════════════════
// AGRUPAR MENSAGENS + PREPARAR SYSTEM MESSAGE
// Combina
  debounce, apresentação e tools em um único node
// ════════════════════════════════════════════════════════

const messages =
  $input.all().map(item => item.json.message_text).join('\n');
const instanceData = $('Processar Dados Instância').item.json;

// Detecta   
  primeira mensagem (saudação)
const mensagemCliente = messages.toLowerCase();
const saudacoesIniciais = ['oi', 'olá', 'ola', 'bom dia', 'boa 
  tarde', 'boa noite', 'hey', 'opa', 'alo', 'alô'];
const isPrimeira = saudacoesIniciais.some(s => mensagemCliente.includes(s)) &&
  messages.length < 50;

// Saudação por horário (UTC-3)
const agora = new Date();
const hora = (agora.getUTCHours() - 3 + 24) % 24;
const 
  saudacao = hora < 12 ? 'Bom dia' : hora < 18 ? 'Boa tarde' : 'Boa noite';
const nome = instanceData.remetente_nome || '';

// ════════     
  FUNÇÃO DE REPLACE DAS VARIÁVEIS ════════
const replaceVars = (text) => {
  if (!text) return '';
  return text

  .replace(/\{\{nome_cliente\}\}/g, nome || 'Cliente')
    .replace(/\{\{numero_cliente\}\}/g, instanceData.remetente_numero || '')

    .replace(/\{\{nome_organizacao\}\}/g, instanceData.organizacao_nome || '')
    .replace(/\{\{nome_agente\}\}/g,
  instanceData.instance_name || '')
    .replace(/\{\{saudacao\}\}/g, saudacao);
};

// ════════ REPLACE NOS CAMPOS CONFIGURÁVEIS       
  ════════
const personality = replaceVars(instanceData.personality);
const apresentacaoTemplate =
  replaceVars(instanceData.apresentacao);

// ════════ APRESENTAÇÃO (Primeira interação) ════════
const apresentacao = apresentacaoTemplate

    ? `\n🎯 PRIMEIRA INTERAÇÃO - Apresente-se assim:\n"${apresentacaoTemplate}"\n\nREGRAS:\n- Tom caloroso e amigável\n- SEMPRE
  incentive agendamento\n- Use nome do cliente\n- Seja PROATIVO\n- Celebre decisões\n`
  : `\n🎯 PRIMEIRA INTERAÇÃO:\n- Cumprimente com  
  "${saudacao}${nome ? `, ${nome}` : ''}"\n- Apresente-se brevemente\n- Ofereça ajuda para agendar\n`;

// ════════ CONTINUAÇÃO
  ════════
const continuacao = `\n📋 CONVERSA EM ANDAMENTO\n- NÃO se reapresente\n- Continue caloroso\n- Foco em AGENDAR\n- Sugira próximo
   passo sempre\n`;

// ════════ SYSTEM MESSAGE COMPLETO ════════
const systemMessage =
  `\n${personality}\n\n${instanceData.knowledge_base_text}\n\n${instanceData.tools_info}\n\nEmpresa:
  ${instanceData.organizacao_nome}\nAgente: ${instanceData.instance_name}\nCliente: ${nome || 'Cliente'}\nPeríodo:
  ${saudacao}\n\n${isPrimeira ? apresentacao : continuacao}\n\nESSENCIAL:\n1. Tom: caloroso, amigável, proativo\n2. Objetivo: AGENDAR     
  sempre\n3. Formato: *negrito*, emojis (😊✨🎉📅)\n4. Nome do cliente quando tiver\n5. Celebre decisões\n6. Sugira próximos passos\n7.    
  NUNCA invente informações - use as ferramentas disponíveis\n8. Se não tiver ferramenta habilitada, informe que não pode ajudar com aquele    
  assunto específico\n`;

return [{
  json: {
    agrupado_texto: messages,
    remetente_numero: instanceData.remetente_numero,

  remetente_nome: instanceData.remetente_nome,
    system_message: systemMessage,
    tools_enabled: instanceData.tools_enabled,

  instance_name: instanceData.instance_name,
    organizacao_id: instanceData.organizacao_id,
    organizacao_nome: instanceData.organizacao_nome,
    telefone_limpo: instanceData.telefone_limpo,
    remotejid: instanceData.remotejid || instanceData.remetente_numero
  }
}];
